@startuml

abstract class DaoSupport {
  + void save(Object e)
  + void delete(Integer id)
}

interface PersonService {
  + void delete(Integer id)
}

class PersonServiceBean {
  + void delete(Integer id)
}

PersonServiceBean --|> DaoSupport : 泛化即继承关系
PersonServiceBean ..|> PersonService : 实现关系

@enduml
